firmware_template.source:
#include "scd40.h"
#include <Wire.h>
#include <SensirionI2CScd4x.h>
static SensirionI2CScd4x scd;
static uint16_t _co2=0;static float _t=0,_h=0;
static unsigned long _last=0;
void scd40_setup(){Wire.begin();scd.begin(Wire);scd.stopPeriodicMeasurement();scd.startPeriodicMeasurement();Serial.println("[scd40] OK");}
void scd40_loop(){if(millis()-_last<5000)return;_last=millis();bool ready=false;scd.getDataReadyFlag(ready);if(ready)scd.readMeasurement(_co2,_t,_h);}
uint16_t scd40_get_co2(){return _co2;}
float scd40_get_temperature(){return _t;}
float scd40_get_humidity(){return _h;}
